use std::io;
use std::str::FromStr;

use std::io::prelude::*;
use std::io::BufReader;
use std::cmp::{max, min};

fn get_line() -> String {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input
}

fn get_vec<T>() -> Vec<T>
where T: FromStr,
      <T as FromStr>::Err: std::fmt::Debug,
{
    get_line().split_whitespace().map(|k| k.parse().unwrap()).collect()
}

const N: i64 = 998_244_353;

fn extended_euclid(a: i64, b: i64) -> (i64, i64, i64) {
    if b == 0 {
        (a, 1, 0)
    } else {
        let (d0, x0, y0) = extended_euclid(b, a % b);
        (d0, y0, x0 - a / b * y0)
    }
}

fn main() {
    let (a, b, c) = {
        let input = get_line();
        let mut it = input.split_whitespace().map(|k| k.parse::<i64>().unwrap());
        (
            it.next().unwrap(),
            it.next().unwrap(),
            it.next().unwrap(),
            )
    };

    let mut s = [a, b, c];
    s.sort();
    let (a, b, c) = (s[0], s[1], s[2]);

    // Nombres d'arêtes possibles :
    // a * b + b * c + c * a
    // Nombre de combinaisons possibles :
    // 2^nap

    let modulo = |a, b| {
        if a % b < 0 {
            a % b + b
        } else {
            a % b
        }
    };

    let inv = |x| {
        modulo(extended_euclid(x, N).1, N)
    };

    let fact: Vec<i64> = (0..5001).scan(1, |state, x| {
        if x != 0 {
            *state = x * *state % N;
        }
        Some(*state)
    }).collect();

    let bc = |k, n| {
        fact[n as usize] * inv(fact[(n - k) as usize]) % N * inv(fact[k as usize]) % N
    };

    let np = |k, n| {
        fact[n as usize] * inv(fact[(n - k) as usize]) % N
    };

    let foo = |a, b| {
        (0..a + 1).map(|i| bc(i, a) * np(i, b) % N).fold(0, |acc, x| (acc + x) % N)
    };

    let ans = foo(a, b) * foo(a, c) % N * foo(b, c) % N;
    println!("{}", ans);
}
